#include <vector>
#include <algorithm>
#include <queue>

using namespace std;

long long solve(vector<long long> value, vector<long long> limit) {
    int n = value.size();
    vector<pair<long long, long long>> elements;
    for (int i = 0; i < n; ++i) {
        elements.emplace_back(limit[i], value[i]);
    }
    sort(elements.begin(), elements.end());

    priority_queue<long long> max_heap;
    long long total = 0;
    long long res = 0;
    long long active = 0;
    int i = 0;
    while (i < n || !max_heap.empty()) {
        if (max_heap.empty() && i < n && elements[i].first > active) {
            active = elements[i].first;
        }

        while (i < n && elements[i].first <= active) {
            max_heap.push(elements[i].second);
            i++;
        }

        if (!max_heap.empty()) {
            long long val = max_heap.top();
            max_heap.pop();
            total += val;
            res = max(res, total);
            active++;
        } else {
            break;
        }

        while (i < n && elements[i].first <= active) {
            max_heap.push(elements[i].second);
            i++;
        }
    }

    return res;
}
